mapper.select:
SELECT n.NOTICE_ID, n.NOTICE_TYPE, n.NOTICE_TITLE, n.NOTICE_CONTENTS, n.START_DATE, n.START_TIME, n.END_DATE, n.END_TIME, n.INSERT_USER_ID, n.UPDATE_USER_ID, DATE_FORMAT(n.INSERT_DT, '%Y-%m-%d %H:%i') AS INSERT_DT, DATE_FORMAT(n.UPDATE_DT, '%Y-%m-%d %H:%i') AS UPDATE_DT, iu.LOGIN_ID AS INSERT_LOGIN_ID, uu.LOGIN_ID AS UPDATE_LOGIN_ID, DATE_FORMAT(STR_TO_DATE(CONCAT(n.START_DATE,'',n.START_TIME),'%Y%m%d %H%i'), '%Y-%m-%d %H:%i') AS START_DATETIME, DATE_FORMAT(STR_TO_DATE(CONCAT(n.END_DATE,'',n.END_TIME),'%Y%m%d %H%i'), '%Y-%m-%d %H:%i') AS END_DATETIME FROM NOTICE n LEFT JOIN USER_BASIC iu ON n.INSERT_USER_ID = iu.USER_ID LEFT JOIN USER_BASIC uu ON n.UPDATE_USER_ID = uu.USER_ID WHERE 1 = 1
AND notice_type = #{noticeType}
AND notice_title LIKE CONCAT('%', #{keyword}, '%')
AND NOTICE_CONTENTS LIKE CONCAT('%', #{keyword}, '%')
AND ( notice_title LIKE CONCAT('%', #{keyword}, '%') OR NOTICE_CONTENTS LIKE CONCAT('%', #{keyword}, '%') )
AND notice_type NOT IN
#{item}
AND STR_TO_DATE(CONCAT(n.START_DATE, ' ', n.START_TIME), '%Y%m%d %H%i') <= NOW() AND STR_TO_DATE(CONCAT(n.END_DATE, ' ', n.END_TIME), '%Y%m%d %H%i') >= NOW()
ORDER BY CASE WHEN n.UPDATE_DT IS NOT NULL THEN n.UPDATE_DT ELSE n.INSERT_DT END DESC, n.NOTICE_ID DESC LIMIT #{limit} OFFSET #{offset}

SELECT n.NOTICE_ID, n.NOTICE_TYPE, n.NOTICE_TITLE, n.NOTICE_CONTENTS, n.START_DATE, n.START_TIME, n.END_DATE, n.END_TIME, n.INSERT_USER_ID, DATE_FORMAT(n.INSERT_DT, '%Y-%m-%d %H:%i:%s') AS INSERT_DT, DATE_FORMAT(n.UPDATE_DT, '%Y-%m-%d %H:%i:%s') AS UPDATE_DT, u.LOGIN_ID, DATE_FORMAT(STR_TO_DATE(CONCAT(n.START_DATE, ' ', n.START_TIME), '%Y%m%d %H%i'), '%Y-%m-%d %H:%i') AS startDatetime, DATE_FORMAT(STR_TO_DATE(CONCAT(n.END_DATE, ' ', n.END_TIME), '%Y%m%d %H%i'), '%Y-%m-%d %H:%i') AS endDatetime FROM NOTICE n LEFT JOIN USER_BASIC u ON n.INSERT_USER_ID = u.USER_ID WHERE n.NOTICE_ID = #{noticeId}
AND notice_type NOT IN
#{item}
AND NOW() BETWEEN STR_TO_DATE(CONCAT(n.START_DATE, ' ', n.START_TIME), '%Y%m%d %H%i') AND STR_TO_DATE(CONCAT(n.END_DATE, ' ', n.END_TIME), '%Y%m%d %H%i')

